if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $input.first().json.body || $input.first().json || {};
const id = body.id || body.opportunity_id || null;
if (!id) throw new Error('MISSING_ID: opportunity id is required');
return [{ json: { id: id, dryRun: body.dryRun === true, requested_at: new Date().toISOString() } }];

const opp = $('Fetch Opportunity').first().json || {};
const allSources = $('Fetch Sources').all() || [];
const sources = allSources.map(function(i) { return i.json; }).filter(function(s) { return s && s.id; });
const allSaved = $('Fetch Saved Analysis').all() || [];
const savedRow = allSaved.map(function(i) { return i.json; }).filter(function(r) { return r && !r.error && r.summary; })[0] || null;

const emptyOODA = function(reason) {
  return {
    observe: { summary: reason, facts: [], gaps: ['Source coverage is insufficient. Additional records needed.'], coverage_note: 'thin' },
    orient: { summary: reason, context: [], risks: [], coverage_note: 'thin' },
    decide: { summary: reason, recommendation: 'watch', priority: 'low', rationale: [], coverage_note: 'thin' },
    act: { summary: reason, next_steps: [{ step: 'Gather additional source records before taking action.', urgency: 'when available' }], owner_suggestions: [], coverage_note: 'thin' }
  };
};

var analysis, ooda, needsOODACall;

if (savedRow) {
  analysis = { summary: savedRow.summary || '', why_it_matters: savedRow.why_it_matters || null, recommendation: savedRow.recommendation || 'review', confidence: savedRow.confidence || null, last_analyzed_at: savedRow.last_analyzed_at || null };
  var parsedOODA = null;
  if (savedRow.ooda_json) {
    try { parsedOODA = typeof savedRow.ooda_json === 'string' ? JSON.parse(savedRow.ooda_json) : savedRow.ooda_json; } catch(e) { parsedOODA = null; }
  }
  ooda = (parsedOODA && parsedOODA.observe && parsedOODA.orient && parsedOODA.decide && parsedOODA.act) ? parsedOODA : emptyOODA('Saved analysis exists but OODA block is missing. Re-analysis queued.');
  needsOODACall = !parsedOODA;
} else {
  analysis = { summary: 'Analysis is being generated. Refresh shortly.', why_it_matters: null, recommendation: 'pending', confidence: null, last_analyzed_at: null };
  ooda = emptyOODA('OODA analysis is being generated. Refresh this page shortly.');
  needsOODACall = true;
}

return [{ json: { opp: opp, sources: sources, analysis: analysis, ooda: ooda, learning: { source_count: sources.length, analyst_feedback: null, learning_notes: null }, needsOODACall: needsOODACall } }];

const assembled = $('Assemble OODA').first().json;
const opp = assembled.opp;
const sources = assembled.sources;
const learning = assembled.learning;
var analysis = assembled.analysis;
var ooda = assembled.ooda;

if (assembled.needsOODACall) {
  const fresh = $('Call OODA Workflow').first().json || {};
  if (fresh.observe_summary) {
    analysis = { summary: fresh.summary || analysis.summary, why_it_matters: fresh.orient_opportunity || null, recommendation: String(fresh.decide_recommendation || 'review').toLowerCase(), confidence: Number(fresh.confidence_score || 0) / 100, last_analyzed_at: fresh.generated_at || new Date().toISOString() };
    ooda = {
      observe: { summary: fresh.observe_summary || '', facts: (fresh.observe_key_signals || []).map(function(s){return{text:s,source_backed:false,interpretation:true};}), gaps: [], coverage_note: 'partial' },
      orient: { summary: fresh.orient_threat || '', context: (fresh.orient_capability_gaps || []).map(function(g){return{text:g,source_backed:false,interpretation:true};}), risks: [], coverage_note: 'partial' },
      decide: { summary: (fresh.decide_rationale || []).join('. '), recommendation: String(fresh.decide_recommendation || 'watch').toLowerCase(), priority: 'medium', rationale: (fresh.decide_rationale || []).map(function(r){return{text:r,source_backed:false,interpretation:true};}), coverage_note: 'partial' },
      act: { summary: String((fresh.act_immediate || []).slice(0,1).join('')), next_steps: (fresh.act_immediate || []).map(function(s){return{step:s,urgency:'immediate'};}).concat((fresh.act_capture || []).map(function(s){return{step:s,urgency:'this month'};})), owner_suggestions: [], coverage_note: 'partial' }
    };
  }
}

return [{ json: { success: true, workflow: 'opportunity-detail-v1', action: 'get_opportunity_detail', dryRun: false, data: { opportunity: opp, analysis: analysis, ooda: ooda, sources: sources, learning: learning }, meta: { generated_at: new Date().toISOString(), source_count: sources.length, ooda_coverage: ooda.observe.coverage_note || 'thin', analysis_confidence: analysis.confidence }, error: null } }];
